import React, { useState } from "react";
import logo from "./logo.png"; // Adjust the path based on your folder structure

function App() {
  const [activeForm, setActiveForm] = useState("login");

  const [formData, setFormData] = useState({
    email: "",
    password: "",
    confirmPassword: "",
  });

  const handleFormSwitch = (form) => {
    setActiveForm(form);
    setFormData({ email: "", password: "", confirmPassword: "" });
  };

  const handleSubmit = (event) => {
    event.preventDefault();
    if (activeForm === "signup" && formData.password !== formData.confirmPassword) {
      alert("Passwords do not match");
      return;
    }
    alert(`${activeForm === "login" ? "Logged In" : "Account Created"} Successfully!`);
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  return (
    <div style={styles.container}>
      <img src={logo} alt="Logo" style={styles.logo} /> {/* Add logo */}
      <h1>{activeForm === "login" ? "Login" : "Create Account"}</h1>
      <form onSubmit={handleSubmit} style={styles.form}>
        <input
          type="email"
          name="email"
          placeholder="Email"
          value={formData.email}
          onChange={handleInputChange}
          style={styles.input}
          required
        />
        <input
          type="password"
          name="password"
          placeholder="Password"
          value={formData.password}
          onChange={handleInputChange}
          style={styles.input}
          required
        />
        {activeForm === "signup" && (
          <input
            type="password"
            name="confirmPassword"
            placeholder="Confirm Password"
            value={formData.confirmPassword}
            onChange={handleInputChange}
            style={styles.input}
            required
          />
        )}
        <button type="submit" style={styles.button}>
          {activeForm === "login" ? "Login" : "Sign Up"}
        </button>
      </form>
      <p style={styles.toggleText}>
        {activeForm === "login" ? "Don't have an account?" : "Already have an account?"} &nbsp;
        <button
          type="button"
          onClick={() => handleFormSwitch(activeForm === "login" ? "signup" : "login")}
          style={styles.toggleButton}
        >
          {activeForm === "login" ? "Create Account" : "Login"}
        </button>
      </p>
    </div>
  );
}

const styles = {
  container: {
    fontFamily: "Arial, sans-serif",
    maxWidth: "400px",
    margin: "0 auto",
    textAlign: "center",
    padding: "20px",
    border: "1px solid #ccc",
    borderRadius: "8px",
    boxShadow: "0 2px 5px rgba(0,0,0,0.1)",
  },
  logo: {
    width: "100px",
    marginBottom: "20px",
  },
  form: {
    display: "flex",
    flexDirection: "column",
    gap: "10px",
  },
  input: {
    padding: "10px",
    fontSize: "16px",
    borderRadius: "4px",
    border: "1px solid #ccc",
  },
  button: {
    padding: "10px",
    fontSize: "16px",
    backgroundColor: "#007BFF",
    color: "white",
    border: "none",
    borderRadius: "4px",
    cursor: "pointer",
  },
  toggleText: {
    marginTop: "10px",
  },
  toggleButton: {
    fontSize: "16px",
    color: "#007BFF",
    background: "none",
    border: "none",
    cursor: "pointer",
  },
};

export default App;
